import boto3

# Create a low-level service client
sns = boto3.client('sns')

def add_subscription(topic, user_provided_url):
    # Use the subscribe method to create new subscriptions
    response = sns.subscribe(
        TopicArn=topic,
        Protocol='https',
        Endpoint=user_provided_url
    )
    
    if 'SubscriptionArn' in response:
        print("Subscription created successfully with ARN:", response['SubscriptionArn'])
    else:
        print("Failed to create subscription. Response: ", response)

# Accept user input for topic and endpoint URL
topic = input("Enter the SNS TopicARN: ")
user_provided_url = input("Enter the Subscription Endpoint URL (https): ")
add_subscription(topic, user_provided_url)